<template><div class="page-content" v-if="project"><PageHeader eyebrow="DevCenter · Project workspace" :title="project.name" :description="project.description||'在 Project 治理边界内完成应用交付。'"><el-button @click="$router.push(`/project-center/projects/${project.id}`)">查看治理配置</el-button><el-button type="primary" @click="$router.push(`/devcenter/projects/${project.id}/applications/new`)">＋ 创建 Application</el-button></PageHeader><div class="boundary-bar surface"><div><small>CLUSTER</small><b>{{project.clusters?.find(c=>c.is_default)?.name||'Not configured'}}</b></div><div><small>ENVIRONMENTS</small><b>{{project.environments?.map(e=>e.environment_name).join(' · ')}}</b></div><div><small>REGISTRY</small><b>{{project.registries?.find(r=>r.is_default)?.image_prefix||'Not configured'}}</b></div></div><section class="surface app-table"><div class="surface-header"><div><h3>Applications</h3><p>仅展示当前 Project 内的应用</p></div><span>{{applications.length}} services</span></div><el-table v-if="applications.length" :data="applications" @row-click="openApplication"><el-table-column prop="name" label="Application" min-width="180"/><el-table-column prop="repo_url" label="Repository" min-width="280"/><el-table-column prop="framework" label="Framework" width="130"/><el-table-column prop="namespace" label="Namespace" width="150"/><el-table-column label="Status" width="130"><template #default="{row}"><StatusBadge :status="row.latest_execution?.status||row.status"/></template></el-table-column></el-table><EmptyState v-else title="当前 Project 还没有 Application" description="创建应用时将自动继承 Project 的环境、集群、Namespace 和 Registry。"><el-button type="primary" @click="$router.push(`/devcenter/projects/${project.id}/applications/new`)">创建 Application</el-button></EmptyState></section></div></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{useRoute,useRouter}from'vue-router';import{projectApi}from'../api/project';import{applicationApi}from'../api/application';import type{Project,Application}from'../types';import PageHeader from'../components/common/PageHeader.vue';import StatusBadge from'../components/common/StatusBadge.vue';import EmptyState from'../components/common/EmptyState.vue';const route=useRoute(),router=useRouter(),project=ref<Project>(),applications=ref<Application[]>([]);const id=Number(route.params.projectId||route.params.id);function openApplication(row:Application){router.push(`/devcenter/projects/${id}/applications/${row.id}`)}onMounted(async()=>{[project.value,applications.value]=await Promise.all([projectApi.get(id),applicationApi.list(id)])});</script>
<style scoped>.boundary-bar{display:grid;grid-template-columns:1fr 1fr 1.4fr;margin-bottom:14px;padding:15px 20px;box-shadow:none}.boundary-bar div{padding:0 18px;border-right:1px solid var(--border-soft)}.boundary-bar div:last-child{border:0}.boundary-bar small,.boundary-bar b{display:block}.boundary-bar small{font-size:10px;color:var(--subtle);letter-spacing:1px}.boundary-bar b{margin-top:6px;font-size:12px;overflow:hidden;text-overflow:ellipsis}.app-table{overflow:hidden}.surface-header>span{font-size:12px;color:var(--muted)}</style>
